import React, { useMemo, useState, useRef, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Transaction } from '../../types';
import { 
    ArrowLeft, Edit2, Trash2, Copy, Calendar, Clock, 
    CreditCard, ArrowUpRight, ArrowDownLeft, 
    ArrowRightLeft, Receipt, CheckCircle2, Wallet, MapPin, ExternalLink,
    Layers, Plus, Minus, Crosshair, Globe, Navigation,
    Car, Gauge, Droplets, Route, Fuel, Info, Maximize2, X
} from 'lucide-react';
import DescriptionModal from './DescriptionModal';

// Declare Leaflet for the preview map
declare const L: any;

interface TransactionDetailPageProps {
    transaction: Transaction;
    onBack: () => void;
    onEdit: (t: Transaction) => void;
    onDelete: (id: string) => void;
    onDuplicate: (t: Transaction) => void;
}

// --- Internal Component: Full Screen Interactive Map ---
const InteractiveMapModal: React.FC<{ 
    location: { lat: number; lng: number; name?: string }; 
    onClose: () => void; 
}> = ({ location, onClose }) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapInstanceRef = useRef<any>(null);
    const tileLayerRef = useRef<any>(null);
    const [mapLayer, setMapLayer] = useState<'standard' | 'satellite' | 'dark'>('standard');
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);

    useEffect(() => {
        if (!mapContainerRef.current) return;

        // Initialize map without setting view immediately to avoid layout thrashing
        const map = L.map(mapContainerRef.current, {
            zoomControl: false,
            attributionControl: false
        });

        mapInstanceRef.current = map;

        // Custom Icon
        const customIcon = L.divIcon({
            className: 'custom-map-marker',
            html: `<div style="
                width: 40px; 
                height: 40px; 
                background-color: #ef4444; 
                border-radius: 50% 50% 50% 0;
                transform: rotate(-45deg);
                border: 3px solid white; 
                box-shadow: 0 4px 6px rgba(0,0,0,0.3);
                display: flex; 
                align-items: center; 
                justify-content: center;
                color: white;
            ">
                <div style="width: 14px; height: 14px; background: white; border-radius: 50%;"></div>
            </div>`,
            iconSize: [40, 40],
            iconAnchor: [20, 40],
        });

        L.marker([location.lat, location.lng], { icon: customIcon }).addTo(map);
        updateTileLayer(map, 'standard');

        // CRITICAL FIX: Invalidate size and set view after a short delay to ensure modal transition is done
        // and container has correct dimensions.
        setTimeout(() => {
            if (map) {
                map.invalidateSize();
                map.setView([location.lat, location.lng], 16);
            }
        }, 150);

        return () => {
            if (mapInstanceRef.current) {
                mapInstanceRef.current.remove();
                mapInstanceRef.current = null;
            }
        };
    }, [location]);

    const updateTileLayer = (map: any, layerType: 'standard' | 'satellite' | 'dark') => {
        if (tileLayerRef.current) map.removeLayer(tileLayerRef.current);

        let url = '';
        switch (layerType) {
            case 'satellite':
                url = 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}';
                break;
            case 'dark':
                url = 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png';
                break;
            case 'standard':
            default:
                url = 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png';
                break;
        }
        tileLayerRef.current = L.tileLayer(url, { maxZoom: 19 }).addTo(map);
    };

    const handleLayerChange = (type: 'standard' | 'satellite' | 'dark') => {
        setMapLayer(type);
        if (mapInstanceRef.current) updateTileLayer(mapInstanceRef.current, type);
        setIsLayerMenuOpen(false);
    };

    const handleZoom = (dir: 'in' | 'out') => {
        if (!mapInstanceRef.current) return;
        if (dir === 'in') mapInstanceRef.current.zoomIn();
        else mapInstanceRef.current.zoomOut();
    };

    const handleRecenter = () => {
        if (mapInstanceRef.current) {
            mapInstanceRef.current.flyTo([location.lat, location.lng], 16, { duration: 1 });
        }
    };

    // Use Portal to render outside the parent's stacking context (created by transform animations)
    return createPortal(
        <div className="fixed inset-0 z-[100] flex flex-col bg-white dark:bg-[#121212] animate-fade-in-up h-[100dvh]">
            {/* Header */}
            <div className="absolute top-0 left-0 right-0 z-20 p-4 flex justify-between items-start pointer-events-none">
                <div className="bg-white/90 dark:bg-[#1e1f22]/90 backdrop-blur-md px-4 py-3 rounded-2xl shadow-lg border border-gray-200 dark:border-gray-800 pointer-events-auto max-w-[70%]">
                     <h3 className="text-sm font-bold text-gray-900 dark:text-white line-clamp-1">{location.name || "Selected Location"}</h3>
                     <p className="text-xs text-gray-500 dark:text-gray-400 font-mono mt-0.5">{location.lat.toFixed(6)}, {location.lng.toFixed(6)}</p>
                </div>
                <button 
                    onClick={onClose}
                    className="pointer-events-auto p-2.5 rounded-full bg-white dark:bg-[#1e1f22] shadow-lg text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors"
                >
                    <X className="w-6 h-6" />
                </button>
            </div>

            {/* Map */}
            <div className="flex-1 relative bg-neutral-100 dark:bg-neutral-900 overflow-hidden">
                <div ref={mapContainerRef} className="absolute inset-0 z-0" />

                {/* Controls */}
                <div className="absolute right-4 bottom-8 z-10 flex flex-col gap-3 pointer-events-none items-end">
                     {/* Directions */}
                     <a 
                        href={`https://www.google.com/maps/search/?api=1&query=${location.lat},${location.lng}`} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="pointer-events-auto flex items-center gap-2 px-4 py-3 bg-blue-600 hover:bg-blue-700 text-white rounded-full shadow-lg font-bold text-sm transition-all mb-2"
                    >
                        <Navigation className="w-4 h-4" />
                        Directions
                    </a>

                     {/* Layer Switcher */}
                     <div className="pointer-events-auto relative">
                        <button 
                            onClick={() => setIsLayerMenuOpen(!isLayerMenuOpen)}
                            className={`w-12 h-12 rounded-xl bg-white dark:bg-[#1e1f22] shadow-md flex items-center justify-center border-2 border-white dark:border-[#2d2e33] transition-all hover:bg-gray-50 dark:hover:bg-gray-800 ${isLayerMenuOpen ? 'text-indigo-600' : 'text-gray-600 dark:text-gray-300'}`}
                        >
                            <Layers className="w-6 h-6" />
                        </button>
                        {isLayerMenuOpen && (
                            <div className="absolute bottom-full right-0 mb-3 p-2 bg-white dark:bg-[#1e1f22] rounded-xl shadow-xl border border-gray-100 dark:border-gray-800 flex flex-col gap-1 w-32 animate-fade-in-up">
                                <button onClick={() => handleLayerChange('standard')} className={`flex items-center gap-2 px-2 py-2 rounded-lg text-xs font-bold ${mapLayer === 'standard' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5'}`}>
                                    <MapPin className="w-3 h-3" /> Standard
                                </button>
                                <button onClick={() => handleLayerChange('satellite')} className={`flex items-center gap-2 px-2 py-2 rounded-lg text-xs font-bold ${mapLayer === 'satellite' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5'}`}>
                                    <Globe className="w-3 h-3" /> Satellite
                                </button>
                                <button onClick={() => handleLayerChange('dark')} className={`flex items-center gap-2 px-2 py-2 rounded-lg text-xs font-bold ${mapLayer === 'dark' ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-400' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5'}`}>
                                    <Layers className="w-3 h-3" /> Dark
                                </button>
                            </div>
                        )}
                    </div>

                    {/* Zoom Controls */}
                    <div className="pointer-events-auto flex flex-col bg-white dark:bg-[#1e1f22] rounded-xl shadow-md overflow-hidden border border-gray-100 dark:border-gray-800">
                        <button onClick={() => handleZoom('in')} className="w-12 h-12 flex items-center justify-center text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 active:bg-gray-200">
                            <Plus className="w-6 h-6" />
                        </button>
                        <div className="h-px bg-gray-200 dark:bg-gray-700 w-full" />
                        <button onClick={() => handleZoom('out')} className="w-12 h-12 flex items-center justify-center text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 active:bg-gray-200">
                            <Minus className="w-6 h-6" />
                        </button>
                    </div>

                    {/* Recenter */}
                    <button 
                        onClick={handleRecenter}
                        className="pointer-events-auto w-12 h-12 rounded-xl bg-white dark:bg-[#1e1f22] shadow-md flex items-center justify-center text-gray-600 dark:text-gray-300 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors border border-gray-200 dark:border-gray-700"
                    >
                        <Crosshair className="w-6 h-6" />
                    </button>
                </div>
            </div>
        </div>,
        document.body
    );
}

