                         <div className="flex items-center gap-2 mb-4 relative z-10">
                            <div className={`p-2 ${theme.iconBg} rounded-full ${theme.text}`}>
                                <MapPin className="w-5 h-5" />
                            </div>
                            <h3 className="font-bold text-gray-900 dark:text-white text-base">Location Details</h3>
                        </div>

                        {/* Static Map Container */}
                        <div className="relative w-full h-48 rounded-xl overflow-hidden border border-white/50 dark:border-white/10 shadow-sm cursor-pointer" onClick={() => setIsFullScreenMapOpen(true)}>
                            <div ref={staticMapRef} className="absolute inset-0 z-0 bg-neutral-200 dark:bg-neutral-800 pointer-events-none" />

                            {/* Click to Expand Overlay */}
