import React, { useEffect, useRef, useState, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { X, Navigation, Layers, Crosshair, MapPin, RotateCcw, Loader2, Car, Bike, Footprints, Compass } from 'lucide-react';

// Declare Leaflet types
declare const L: any;

interface MapModalProps {
    targetLocation: { lat: number; lng: number; name?: string };
    onClose: () => void;
}

interface RouteStats {
    distanceMeters: number;
    durationSeconds: number; // Raw duration from OSRM (driving)
}

type TravelMode = 'driving' | 'cycling' | 'walking';

const MapModal: React.FC<MapModalProps> = ({ targetLocation, onClose }) => {
    const mapContainerRef = useRef<HTMLDivElement>(null);
    const mapWrapperRef = useRef<HTMLDivElement>(null); // Wrapper for rotation
    const mapInstanceRef = useRef<any>(null);
    const userMarkerRef = useRef<any>(null);
    const routeLayerRef = useRef<any>(null);
    const routeBackgroundLayerRef = useRef<any>(null);
    const tileLayerRef = useRef<any>(null);
    const watchIdRef = useRef<number | null>(null);

    const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
    const [mapLayer, setMapLayer] = useState<'standard' | 'satellite' | 'dark'>('standard');
    const [isLayerMenuOpen, setIsLayerMenuOpen] = useState(false);
    const [routeStats, setRouteStats] = useState<RouteStats | null>(null);
    const [isLoadingRoute, setIsLoadingRoute] = useState(false);
    const [error, setError] = useState<string | null>(null);

    // Navigation States
    const [travelMode, setTravelMode] = useState<TravelMode>('driving');
    const [isNavigating, setIsNavigating] = useState(false);
    const [isHeadsUp, setIsHeadsUp] = useState(true); // Toggle for map rotation
    const [gpsHeading, setGpsHeading] = useState<number>(0);
    const [deviceHeading, setDeviceHeading] = useState<number>(0); // Compass
    const [currentSpeed, setCurrentSpeed] = useState<number>(0);

    // Derived state: Moving if speed > 0.8 m/s (~3 km/h) to filter GPS noise
    const isMoving = currentSpeed > 0.8;

    // 1. Initialize Map
    useEffect(() => {
        if (!mapContainerRef.current) return;

        const map = L.map(mapContainerRef.current, {
            zoomControl: false,
            attributionControl: false,
            zoomAnimation: true,
            markerZoomAnimation: true,
        });

        mapInstanceRef.current = map;

        // Destination Marker (Red Pin with checkered pattern hint)
        const targetIcon = L.divIcon({
            className: 'custom-map-marker',
            html: `<div style="
                width: 36px; 
                height: 36px; 
                background-color: #ef4444; 
                border-radius: 50% 50% 50% 0;
                transform: rotate(-45deg);
                border: 3px solid white; 
                box-shadow: 0 4px 8px rgba(0,0,0,0.3);
                display: flex; 
                align-items: center; 
                justify-content: center;
                color: white;
            ">
                <div style="width: 12px; height: 12px; background: white; border-radius: 50%; transform: rotate(45deg);"></div>
            </div>`,
            iconSize: [36, 36],
            iconAnchor: [18, 36],
            popupAnchor: [0, -36]
        });

        L.marker([targetLocation.lat, targetLocation.lng], { icon: targetIcon })
         .addTo(map)
         .bindPopup(`<div class="text-sm font-bold text-neutral-800">${targetLocation.name || "Destination"}</div>`);

        updateTileLayer(map, 'standard');
        map.setView([targetLocation.lat, targetLocation.lng], 15);

        // Fix layout issues
        setTimeout(() => {
            map.invalidateSize();
        }, 100);

        locateUser();

        // Device Orientation (Compass) Listener
        const handleOrientation = (event: DeviceOrientationEvent) => {
            if (event.alpha !== null) {
                // Convert alpha to compass heading (0-360)
                let compass = (event as any).webkitCompassHeading || (360 - event.alpha);
                setDeviceHeading(compass);
            }
        };
        window.addEventListener('deviceorientation', handleOrientation);

        return () => {
            window.removeEventListener('deviceorientation', handleOrientation);
            if (watchIdRef.current !== null) navigator.geolocation.clearWatch(watchIdRef.current);
            if (mapInstanceRef.current) {
                mapInstanceRef.current.remove();
                mapInstanceRef.current = null;
            }
        };
    }, [targetLocation]);

    // 2. Dynamic Map Rotation Logic
    useEffect(() => {
        if (!mapWrapperRef.current) return;

        // Effective Heading: Prioritize GPS when moving, Compass when static
        // If navigating and HeadsUp is enabled, rotate the map so "Forward" is Up.
        let rotation = 0;
        let scale = 1;

        if (isNavigating && isHeadsUp) {
            const effectiveHeading = isMoving ? gpsHeading : deviceHeading;
            rotation = -effectiveHeading; // Rotate map opposite to heading
            scale = 1.4; // Scale up to cover corners during rotation
        }

        mapWrapperRef.current.style.transform = `rotate(${rotation}deg) scale(${scale})`;
    }, [isNavigating, isHeadsUp, isMoving, gpsHeading, deviceHeading]);

    // 3. User Marker Updates
    useEffect(() => {
        if (!userLocation || !mapInstanceRef.current) return;

        // Determine rotation to apply to the MARKER icon.
        // The marker sits inside the map. 
        // If Map is rotated by R, and we want marker to point at Heading H:
        // Marker Visual Rotation = H (relative to world) - R (map rotation)
        // Wait, simpler: We rotate the icon div by H.
        // Since the map wrapper rotates by -H, the net result is the marker points "Up" (0deg) relative to screen.

        const effectiveHeading = isMoving ? gpsHeading : deviceHeading;

        const iconHtml = isNavigating 
            ? // ARROW ICON (Navigation Mode)
              `<div class="arrow-rotator" style="
                  width: 56px; height: 56px; 
                  display: flex; align-items: center; justify-content: center;
                  transition: transform 0.2s linear;
                  transform: rotate(${effectiveHeading}deg);
                  filter: drop-shadow(0 4px 6px rgba(0,0,0,0.3));
              ">
                  <div style="
                      width: 0; 
                      height: 0; 
                      border-left: 12px solid transparent;
                      border-right: 12px solid transparent;
                      border-bottom: 30px solid #3b82f6; 
                      position: relative;
                  ">
                    <div style="
                        position: absolute;
                        top: 18px;
                        left: -12px;
                        width: 24px;
                        height: 24px;
                        background: #2563eb; 
                        border-radius: 50% 50% 0 0;
                        transform: scaleY(0.4);
                    "></div>
                  </div>
              </div>`
            : // BEAM CIRCLE ICON (Static/Overview)
              `<div class="static-rotator" style="
                  position: relative;
                  width: 60px; height: 60px;
                  display: flex; align-items: center; justify-content: center;
                  transition: transform 0.2s linear;
                  transform: rotate(${effectiveHeading}deg);
              ">
                  <!-- Flashlight Beam -->
                  <div style="
                      position: absolute;
                      top: -5px;
                      left: 50%;
                      transform: translateX(-50%);
                      width: 40px;
                      height: 40px;
                      background: radial-gradient(circle at 50% 100%, rgba(59, 130, 246, 0.4), transparent 70%);
                      clip-path: polygon(50% 100%, 0 0, 100% 0);
                      border-radius: 4px;
                  "></div>
                  <!-- Center Dot -->
                  <div style="
                      width: 20px; height: 20px;
                      background-color: #3b82f6;
                      border: 3px solid white;
                      border-radius: 50%;
                      box-shadow: 0 2px 5px rgba(0,0,0,0.3);
                      z-index: 2;
                  "></div>
              </div>`;

        const newIcon = L.divIcon({
            className: 'user-location-marker',
            html: iconHtml,
            iconSize: isNavigating ? [56, 56] : [60, 60],
            iconAnchor: isNavigating ? [28, 28] : [30, 30]
        });

        if (userMarkerRef.current) {
            userMarkerRef.current.setLatLng([userLocation.lat, userLocation.lng]);
            userMarkerRef.current.setIcon(newIcon);
        } else {
            userMarkerRef.current = L.marker([userLocation.lat, userLocation.lng], { icon: newIcon, zIndexOffset: 1000 }).addTo(mapInstanceRef.current);
        }

    }, [userLocation, isMoving, isNavigating, gpsHeading, deviceHeading]);

    // 4. Geolocation Tracking
    const startNavigation = () => {
        setIsNavigating(true);
        if (!navigator.geolocation) return;

        watchIdRef.current = navigator.geolocation.watchPosition(
            (pos) => {
                const { latitude, longitude, heading, speed } = pos.coords;

                setUserLocation({ lat: latitude, lng: longitude });
                if (speed !== null) setCurrentSpeed(speed);
                if (heading !== null && !isNaN(heading)) setGpsHeading(heading);

                // If navigating, lock camera to user (center screen)
                if (mapInstanceRef.current) {
                    mapInstanceRef.current.flyTo([latitude, longitude], 18, {
                        animate: true,
                        duration: 0.5
                    });
                }
            },
            (err) => console.error(err),
            { enableHighAccuracy: true, maximumAge: 0 }
        );
    };

    const stopNavigation = () => {
        setIsNavigating(false);
        if (watchIdRef.current !== null) {
            navigator.geolocation.clearWatch(watchIdRef.current);
            watchIdRef.current = null;
        }
        // Zoom out to show route overview
        handleFitRoute();
    };

    const locateUser = () => {
        navigator.geolocation.getCurrentPosition(
            (pos) => {
                setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude });
                if (!routeStats) {
                    calculateRoute({ lat: pos.coords.latitude, lng: pos.coords.longitude });
                }
                if (mapInstanceRef.current) {
                    mapInstanceRef.current.flyTo([pos.coords.latitude, pos.coords.longitude], 16);
                }
            },
            () => setError("Location access denied."),
            { enableHighAccuracy: true }
        );
    };

    const calculateRoute = async (start: { lat: number; lng: number }) => {
        if (!mapInstanceRef.current) return;
        setIsLoadingRoute(true);
        setError(null);

        try {
            const url = `https://router.project-osrm.org/route/v1/driving/${start.lng},${start.lat};${targetLocation.lng},${targetLocation.lat}?overview=full&geometries=geojson`;
            const response = await fetch(url);
            const data = await response.json();

            if (data.code !== 'Ok' || !data.routes || data.routes.length === 0) throw new Error("No route.");

            const route = data.routes[0];
            setRouteStats({ distanceMeters: route.distance, durationSeconds: route.duration });

            // Layers
            if (routeLayerRef.current) mapInstanceRef.current.removeLayer(routeLayerRef.current);
            if (routeBackgroundLayerRef.current) mapInstanceRef.current.removeLayer(routeBackgroundLayerRef.current);

            const bgLine = L.geoJSON(route.geometry, {
                style: { color: '#3b82f6', weight: 8, opacity: 0.3, lineCap: 'round', lineJoin: 'round' }
            }).addTo(mapInstanceRef.current);
            routeBackgroundLayerRef.current = bgLine;

            const fgLine = L.geoJSON(route.geometry, {
                style: { color: '#2563eb', weight: 4, opacity: 1, lineCap: 'round', lineJoin: 'round' }
            }).addTo(mapInstanceRef.current);
            routeLayerRef.current = fgLine;

            if (!isNavigating) {
                mapInstanceRef.current.fitBounds(fgLine.getBounds(), { padding: [40, 40] });
            }
        } catch (e) {
            console.error("Routing error", e);
        } finally {
            setIsLoadingRoute(false);
        }
    };

    const updateTileLayer = (map: any, layerType: 'standard' | 'satellite' | 'dark') => {
        if (tileLayerRef.current) map.removeLayer(tileLayerRef.current);
        let url = '';
        switch (layerType) {
            case 'satellite': url = 'https://server.arcgisonline.com/ArcGIS/rest/services/World_Imagery/MapServer/tile/{z}/{y}/{x}'; break;
            case 'dark': url = 'https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png'; break;
            case 'standard': default: url = 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png'; break;
        }
        tileLayerRef.current = L.tileLayer(url, { maxZoom: 19 }).addTo(map);
    };

    const handleLayerChange = (type: 'standard' | 'satellite' | 'dark') => {
        setMapLayer(type);
        if (mapInstanceRef.current) updateTileLayer(mapInstanceRef.current, type);
        setIsLayerMenuOpen(false);
    };

    const handleRecenter = () => {
        if (mapInstanceRef.current && userLocation) {
            mapInstanceRef.current.flyTo([userLocation.lat, userLocation.lng], 18);
        } else {
             locateUser();
        }
    };

    const handleFitRoute = () => {
         if (mapInstanceRef.current && routeLayerRef.current) {
             mapInstanceRef.current.fitBounds(routeLayerRef.current.getBounds(), { padding: [50, 50] });
         }
    };

    // Calculate display stats
    const displayStats = useMemo(() => {
        if (!routeStats) return { time: '--', dist: '--' };
        const distKm = (routeStats.distanceMeters / 1000).toFixed(1);
        let seconds = routeStats.durationSeconds;

        if (travelMode === 'cycling') seconds = routeStats.distanceMeters / 4.5;
        else if (travelMode === 'walking') seconds = routeStats.distanceMeters / 1.3;

        const mins = Math.ceil(seconds / 60);
        const hours = Math.floor(mins / 60);
        const remainingMins = mins % 60;

        let timeString = `${mins} min`;
        if (hours > 0) timeString = `${hours} hr ${remainingMins} min`;

        return { time: timeString, dist: `${distKm} km` };
    }, [routeStats, travelMode]);

    return createPortal(
        <div className="fixed inset-0 z-[100] flex flex-col bg-white dark:bg-[#121212] animate-fade-in-up h-[100dvh] overflow-hidden">

            {/* Header Pill */}
            <div className="absolute top-4 left-4 right-4 z-20 pointer-events-none flex justify-between items-start">
                <div className="bg-white/90 dark:bg-[#1e1f22]/90 backdrop-blur-md px-4 py-2.5 rounded-full shadow-lg border border-gray-200 dark:border-gray-800 pointer-events-auto flex items-center gap-3 max-w-[75%]">
                     <div className="p-1.5 bg-red-100 dark:bg-red-900/30 rounded-full text-red-600 dark:text-red-400">
                        <MapPin className="w-3.5 h-3.5 fill-current" />
                     </div>
                     <div className="min-w-0">
                         <h3 className="text-xs font-bold text-gray-900 dark:text-white truncate">{targetLocation.name || "Destination"}</h3>
                     </div>
                </div>
                <button onClick={onClose} className="pointer-events-auto p-2.5 rounded-full bg-white dark:bg-[#1e1f22] shadow-lg text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-800 transition-colors">
                    <X className="w-5 h-5" />
                </button>
            </div>

            {/* Map Area */}
            <div className="flex-1 relative bg-neutral-100 dark:bg-neutral-900 overflow-hidden">
                {/* 
                    Wrapper for rotation. 
                    - transition: smooth rotation. 
                    - width/height 100% -> scaled up in CSS to ensure corners don't show blank space when rotated.
                */}
                <div 
                    ref={mapWrapperRef} 
                    className="absolute inset-0 w-full h-full transition-transform duration-500 ease-out origin-center"
                    style={{ willChange: 'transform' }}
                >
                    <div ref={mapContainerRef} className="absolute inset-0 z-0" />
                </div>

                {/* Controls */}
                <div className="absolute right-4 top-1/2 -translate-y-1/2 z-10 flex flex-col gap-3 pointer-events-none items-end">

                    {/* Compass / Heads Up Toggle */}
                    {isNavigating && (
                        <button 
                            onClick={() => setIsHeadsUp(!isHeadsUp)}
                            className={`pointer-events-auto w-10 h-10 rounded-xl shadow-lg flex items-center justify-center transition-all ${isHeadsUp ? 'bg-indigo-600 text-white' : 'bg-white dark:bg-[#1e1f22] text-gray-600 dark:text-gray-300'}`}
                            title={isHeadsUp ? "Heads Up (Rotating)" : "North Up (Fixed)"}
                        >
                            <Compass className={`w-5 h-5 transition-transform duration-500 ${isHeadsUp ? '' : 'rotate-45'}`} />
                        </button>
                    )}

                    <div className="pointer-events-auto relative">
                        <button onClick={() => setIsLayerMenuOpen(!isLayerMenuOpen)} className={`w-10 h-10 rounded-xl bg-white dark:bg-[#1e1f22] shadow-lg flex items-center justify-center transition-all ${isLayerMenuOpen ? 'text-indigo-600 ring-2 ring-indigo-500' : 'text-gray-600 dark:text-gray-300'}`}>
                            <Layers className="w-5 h-5" />
                        </button>
                        {isLayerMenuOpen && (
                            <div className="absolute right-full top-0 mr-3 p-2 bg-white dark:bg-[#1e1f22] rounded-xl shadow-xl border border-gray-100 dark:border-gray-800 flex flex-col gap-1 w-28 animate-fade-in-up origin-right">
                                {['standard', 'satellite', 'dark'].map((l) => (
                                    <button key={l} onClick={() => handleLayerChange(l as any)} className={`px-3 py-2 rounded-lg text-xs font-bold capitalize text-left hover:bg-gray-100 dark:hover:bg-white/5 ${mapLayer === l ? 'text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/20' : 'text-gray-600 dark:text-gray-300'}`}>{l}</button>
                                ))}
                            </div>
                        )}
                    </div>
                    <button onClick={handleRecenter} className="pointer-events-auto w-10 h-10 rounded-xl bg-white dark:bg-[#1e1f22] shadow-lg flex items-center justify-center text-gray-600 dark:text-gray-300 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors">
                        <Crosshair className="w-5 h-5" />
                    </button>
                    {routeStats && !isNavigating && (
                        <button onClick={handleFitRoute} className="pointer-events-auto w-10 h-10 rounded-xl bg-white dark:bg-[#1e1f22] shadow-lg flex items-center justify-center text-gray-600 dark:text-gray-300 hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors">
                            <RotateCcw className="w-5 h-5" />
                        </button>
                    )}
                </div>
            </div>

            {/* Bottom Panel */}
            <div className="bg-white dark:bg-[#1e1f22] border-t border-gray-200 dark:border-gray-800 p-4 z-20 shadow-[0_-5px_20px_rgba(0,0,0,0.1)] rounded-t-3xl">
                <div className="max-w-md mx-auto">
                    {isNavigating ? (
                        <div className="flex items-center justify-between animate-fade-in-up">
                            <div>
                                <div className="flex items-baseline gap-1">
                                    <span className="text-3xl font-extrabold text-gray-900 dark:text-white font-mono tracking-tight">{displayStats.time}</span>
                                    <span className="text-sm font-medium text-gray-500">to go</span>
                                </div>
                                <div className="flex items-center gap-2 text-sm text-gray-500 mt-1">
                                    <span className="font-bold">{displayStats.dist}</span>
                                    <span>•</span>
                                    <span>{new Date(Date.now() + (routeStats?.durationSeconds || 0) * 1000).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})} arrival</span>
                                </div>
                            </div>
                            <button onClick={stopNavigation} className="px-5 py-3 bg-red-100 dark:bg-red-900/30 text-red-600 dark:text-red-400 rounded-full font-bold text-sm hover:bg-red-200 transition-colors">Exit</button>
                        </div>
                    ) : (
                        <div className="flex flex-col gap-4">
                            <div className="flex bg-gray-100 dark:bg-black/30 p-1 rounded-xl">
                                {[
                                    { id: 'driving', icon: Car, label: 'Car' },
                                    { id: 'cycling', icon: Bike, label: 'Bike' },
                                    { id: 'walking', icon: Footprints, label: 'Walk' }
                                ].map((mode) => (
                                    <button key={mode.id} onClick={() => setTravelMode(mode.id as TravelMode)} className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-lg text-xs font-bold transition-all ${travelMode === mode.id ? 'bg-white dark:bg-gray-800 text-indigo-600 dark:text-indigo-400 shadow-sm' : 'text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'}`}>
                                        <mode.icon className="w-3.5 h-3.5" /> {mode.label}
                                    </button>
                                ))}
                            </div>
                            <div className="flex items-center justify-between">
                                <div>
                                    <p className="text-2xl font-extrabold text-gray-900 dark:text-white font-mono tracking-tight flex items-baseline gap-1">
                                        {displayStats.time}
                                        <span className="text-sm font-sans font-medium text-gray-400 ml-1">({displayStats.dist})</span>
                                    </p>
                                    <p className="text-xs font-medium text-green-600 dark:text-green-400">Fastest route via current traffic</p>
                                </div>
                                <button onClick={startNavigation} disabled={isLoadingRoute || !routeStats} className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full font-bold text-sm shadow-lg shadow-indigo-500/25 flex items-center gap-2 transition-all active:scale-[0.98] disabled:opacity-70 disabled:active:scale-100">
                                    {isLoadingRoute ? <Loader2 className="w-4 h-4 animate-spin" /> : <Navigation className="w-4 h-4 fill-current" />} Start
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            </div>
        </div>,
        document.body
    );
};

export default MapModal;
